import React, { useRef, useState, useEffect } from 'react';
import { ScanStep } from '../types';

interface ScannerProps {
  onComplete: (images: { front: string; upper: string; lower: string }) => void;
}

const Scanner: React.FC<ScannerProps> = ({ onComplete }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [currentStep, setCurrentStep] = useState<ScanStep>(ScanStep.Front);
  const [captured, setCaptured] = useState<{ front: string; upper: string; lower: string }>({
    front: '',
    upper: '',
    lower: ''
  });
  const [streamActive, setStreamActive] = useState(false);

  useEffect(() => {
    let stream: MediaStream | null = null;
    const startCamera = async () => {
      try {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } },
          audio: false
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          setStreamActive(true);
        }
      } catch (err) {
        console.error("Camera error:", err);
      }
    };
    startCamera();
    return () => {
      stream?.getTracks().forEach(track => track.stop());
    };
  }, []);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);

        const newCaptured = { ...captured };
        if (currentStep === ScanStep.Front) {
          newCaptured.front = dataUrl;
          setCurrentStep(ScanStep.Upper);
        } else if (currentStep === ScanStep.Upper) {
          newCaptured.upper = dataUrl;
          setCurrentStep(ScanStep.Lower);
        } else {
          newCaptured.lower = dataUrl;
          onComplete({ ...newCaptured, lower: dataUrl });
        }
        setCaptured(newCaptured);
      }
    }
  };

  const getStepText = () => {
    switch (currentStep) {
      case ScanStep.Front: return "Front Smile";
      case ScanStep.Upper: return "Upper Close-up";
      case ScanStep.Lower: return "Lower Close-up";
    }
  };

  const getStepGuide = () => {
    switch (currentStep) {
      case ScanStep.Front: return "Keep mouth open wide. Align teeth in the oval.";
      case ScanStep.Upper: return "Tilt head back slightly. Focus on top row.";
      case ScanStep.Lower: return "Tilt head down slightly. Focus on bottom row.";
    }
  };

  return (
    <div className="flex-1 flex flex-col relative bg-black rounded-3xl overflow-hidden animate-in fade-in duration-700">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="absolute inset-0 w-full h-full object-cover scale-x-[-1]"
      />

      {/* Scanner Overlay UI */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="scanner-overlay w-full h-full"></div>
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="guide-box w-[70%] h-[40%]"></div>
        </div>
      </div>

      <div className="absolute top-6 left-0 right-0 text-center px-6">
        <div className="bg-white/90 backdrop-blur-md rounded-2xl p-4 inline-block shadow-lg">
          <p className="text-cyan-600 font-bold uppercase tracking-widest text-[10px] mb-1">Step {currentStep + 1} of 3</p>
          <h3 className="text-xl font-bold text-slate-900">{getStepText()}</h3>
          <p className="text-slate-600 text-sm mt-1">{getStepGuide()}</p>
        </div>
      </div>

      <div className="absolute bottom-8 left-0 right-0 flex flex-col items-center px-6 gap-6">
        <div className="flex gap-2">
          {[ScanStep.Front, ScanStep.Upper, ScanStep.Lower].map((s) => (
            <div 
              key={s} 
              className={`h-1.5 w-12 rounded-full transition-all ${s === currentStep ? 'bg-cyan-500 shadow-[0_0_10px_rgba(6,182,212,0.5)]' : s < currentStep ? 'bg-green-500' : 'bg-slate-700'}`} 
            />
          ))}
        </div>

        <div className="flex items-center justify-between w-full">
           <div className="w-12 h-12 rounded-full bg-black/40 border border-white/20 flex items-center justify-center">
              {captured.front && (
                <img src={captured.front} className="w-8 h-8 rounded-full object-cover border border-white/40" />
              )}
           </div>

          <button 
            onClick={takePhoto}
            className="w-20 h-20 rounded-full bg-white flex items-center justify-center p-1 active:scale-90 transition-transform shadow-2xl"
          >
            <div className="w-full h-full rounded-full border-4 border-slate-900 flex items-center justify-center">
               <div className="w-4 h-4 bg-slate-900 rounded-sm"></div>
            </div>
          </button>

          <div className="w-12 h-12"></div>
        </div>
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default Scanner;

import React, { useState, useEffect } from 'react';

const Loader: React.FC = () => {
  const [message, setMessage] = useState("Analyzing surface texture...");
  const messages = [
    "Analyzing surface texture...",
    "Measuring edge translucency...",
    "Calibrating gloss reflectivity...",
    "Estimating dentin exposure...",
    "Checking for micro-wear patterns...",
    "Comparing against age-benchmarks...",
    "Finalizing enamel age report..."
  ];

  useEffect(() => {
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % messages.length;
      setMessage(messages[i]);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex-1 flex flex-col items-center justify-center p-8 space-y-8 animate-in fade-in duration-500">
      <div className="relative">
        <div className="w-32 h-32 border-4 border-cyan-100 rounded-full animate-spin border-t-cyan-600"></div>
        <div className="absolute inset-0 flex items-center justify-center">
          <svg className="w-12 h-12 text-cyan-600 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.618.309a6 6 0 00-3.414 5.414v.353a2 2 0 002 2h6a2 2 0 002-2v-.353a2 2 0 01.586-1.414z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 11c3.5 0 6.5-1.5 6.5-1.5s-1.5-3.5-6.5-3.5-6.5 3.5-6.5 3.5 3 1.5 6.5 1.5z" />
          </svg>
        </div>
      </div>
      <div className="text-center">
        <h3 className="text-xl font-bold text-slate-900 tracking-tight">AI Vision Processing</h3>
        <p className="text-slate-500 mt-2 font-medium h-6">{message}</p>
      </div>
      <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
        <div className="bg-cyan-600 h-full animate-[loading_14s_ease-in-out_infinite]"></div>
      </div>
      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          100% { width: 100%; }
        }
      `}</style>
    </div>
  );
};

export default Loader;

import React from 'react';

interface HeatmapProps {
  image: string;
  zones: { x: number; y: number; severity: 'low' | 'medium' | 'high' }[];
  show: boolean;
}

const Heatmap: React.FC<HeatmapProps> = ({ image, zones, show }) => {
  const getSeverityColor = (sev: string) => {
    switch (sev) {
      case 'high': return 'rgba(239, 68, 68, 0.4)'; // Red
      case 'medium': return 'rgba(245, 158, 11, 0.4)'; // Orange
      case 'low': return 'rgba(16, 185, 129, 0.4)'; // Green
      default: return 'rgba(16, 185, 129, 0.4)';
    }
  };

  const getPulsingClass = (sev: string) => {
    switch (sev) {
      case 'high': return 'animate-ping';
      default: return '';
    }
  };

  return (
    <div className="relative rounded-2xl overflow-hidden border border-slate-200 aspect-[4/3] bg-slate-900">
      <img src={image} className="absolute inset-0 w-full h-full object-cover" />

      {show && zones.map((zone, i) => (
        <div 
          key={i}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 rounded-full blur-xl"
          style={{
            left: `${zone.x}%`,
            top: `${zone.y}%`,
            width: '60px',
            height: '60px',
            backgroundColor: getSeverityColor(zone.severity),
          }}
        >
          <div className={`w-full h-full rounded-full border-2 border-white/20 ${getPulsingClass(zone.severity)}`}></div>
        </div>
      ))}

      <div className="absolute bottom-3 left-3 bg-black/60 backdrop-blur-sm px-3 py-1.5 rounded-full flex items-center space-x-3">
        <div className="flex items-center space-x-1">
          <div className="w-2 h-2 rounded-full bg-emerald-400"></div>
          <span className="text-[10px] text-white font-medium">Safe</span>
        </div>
        <div className="flex items-center space-x-1">
          <div className="w-2 h-2 rounded-full bg-amber-400"></div>
          <span className="text-[10px] text-white font-medium">Wearing</span>
        </div>
        <div className="flex items-center space-x-1">
          <div className="w-2 h-2 rounded-full bg-red-400"></div>
          <span className="text-[10px] text-white font-medium">At Risk</span>
        </div>
      </div>
    </div>
  );
};

export default Heatmap;

import React, { useState } from 'react';
import { AnalysisResult } from '../types';
import Heatmap from './Heatmap';

interface ResultsProps {
  result: AnalysisResult;
  originalImage: string;
  onReScan: () => void;
}

